import axios from "axios";
import { showNotify } from "vant";
import "vant/es/notify/style";
const api = axios.create({
  baseURL:
    process.env.DEV && process.env.VUE_OPEN_PROXY === "true"
      ? "/proxy/"
      : process.env.VUE_APP_API_BASEURL,
  timeout: 1000 * 60,
  responseType: "json",
});

api.interceptors.request.use((request) => {
  const token = localStorage.getItem("pad_token") ?? "";
  /**
   * 全局拦截请求发送前提交的参数
   * 以下代码为示例，在请求头里带上 token 信息
   */
  if (token.trim() !== "" && request.headers) {
    request.headers.Authorization = token;
    // console.log(11, request.headers.Token)
  }
  // 是否将 POST 请求参数进行字符串化处理
  if (request.method === "post") {
    // request.data = qs.stringify(request.data, {
    //   arrayFormat: 'brackets',
    // })
  }
  return request;
});

api.interceptors.response.use(
  (response) => {
    /**
     * 全局拦截请求发送后返回的数据，如果数据有报错则在这做全局的错误提示
     * 假设返回数据格式为：{ status: 1, error: '', data: '' }
     * 规则是当 status 为 1 时表示请求成功，为 0 时表示接口需要登录或者登录状态失效，需要重新登录
     * 请求出错时 error 会返回错误信息
     */

    // if (response.data.state === 401) {
    //     // 这里做错误提示，如果使用了 element plus 则可以使用 Message 进行提示
    //     // ElMessage.error(options)
    //     showNotify({ type: 'danger', message: response.data?.message });
    //     return Promise.reject(response.data)
    // }

    if (response.data.state === 200) {
    } else {
      showNotify({ type: "danger", message: response.data?.message });
      return Promise.resolve(response.data);
    }
    return Promise.resolve(response.data);
  },
  (error) => {
    let message = error.message;
    if (message === "Network Error") {
      message = "后端网络故障";
    } else if (message.includes("timeout")) {
      message = "接口请求超时";
    } else if (message.includes("Request failed with status code")) {
      message = `接口${message.substr(message.length - 3)}异常`;
    }
    showNotify({ type: "danger", message: message });
    return Promise.reject(error);
  }
);
export default api;
